      * Get likes for a specific comment (admin only)
      * @param {Frame} frame
      */
     async getCommentLikes(frame) {
-        const commentId = frame.data.id;
+        const commentId = frame.options.id;
         return await this.service.getCommentLikes(commentId, {
             page: frame.options.page,
             limit: frame.options.limit
"
  },
  {
    "file": "ghost/core/core/server/services/comments/comments-service.js",
    "line": 261,
    "severity": "high",
    "description": "The `getCommentLikes` method queries for a comment but doesn't use the result and doesn't verify the comment exists. Without `require: true`, if the comment doesn't exist, the method silently proceeds and returns empty results instead of throwing an error. This violates the error handling pattern seen in `getCommentByID` which properly checks for existence.",
    "fix_patch": "--- a/ghost/core/core/server/services/comments/comments-service.js
+++ b/ghost/core/core/server/services/comments/comments-service.js
@@ -258,7 +258,7 @@
      * @param {any} options - Query options (page, limit)
      */
     async getCommentLikes(commentId, options = {}) {
-        const comment = await this.models.Comment.findOne({id: commentId});
+        await this.models.Comment.findOne({id: commentId}, {require: true});

         const {page, limit} = options;
         const result = await this.models.CommentLike.findPage({
"
  },
  {
    "file": "ghost/core/core/server/api/endpoints/comment-likes.js",
    "line": 8,
    "severity": "medium",
    "description": "The `browse` endpoint definition is missing the `headers` configuration. Ghost's API framework standard (as seen in comments.js) requires all endpoint actions to explicitly define cache control behavior with `headers: { cacheInvalidate: false }` for read-only operations. This is a compliance violation with Ghost's API conventions.",
    "fix_patch": "--- a/ghost/core/core/server/api/endpoints/comment-likes.js
+++ b/ghost/core/core/server/api/endpoints/comment-likes.js
@@ -8,6 +8,9 @@
         options: [
             'id',
             'page',
             'limit'
         ],
         validation: {
             options: {
                 id: {
                     required: true
                 }
             }
         },
+        headers: {
+            cacheInvalidate: false
+        },
         // Use comment permissions - browsing likes is part of comment moderation
         permissions: {
             docName: 'comments'
"
  }
]

